float DirBands(float px, float py, float dir, int hc, float po)
{
    var wd = dir - MathF.Floor(dir);
    var sec = Math.Min(3, (int)MathF.Floor(wd * 4f));
    var bl = SmoothStep(wd * 4f - sec);
    var h = Math.Max(1, hc);
    var hz = 0.5f + 0.5f * MathF.Sin(px * h + po);
    var dd = 0.5f + 0.5f * MathF.Sin((px + py) * h + po);
    var vt = 0.5f + 0.5f * MathF.Sin(py * h + po);
    var du = 0.5f + 0.5f * MathF.Sin((px - py) * h + po);
    return sec switch
    {
        0 => Lerp(hz, dd, bl),
        1 => Lerp(dd, vt, bl),
        2 => Lerp(vt, du, bl),
        _ => Lerp(du, hz, bl)
    };
}

float Sel(float t, float c0, float c1, float c2, float c3, float c4)
{
    if (t < 0.18f) return Lerp(c0, c1, SmoothStep(0.02f, 0.18f, t));
    if (t < 0.45f) return Lerp(c1, c2, SmoothStep(0.18f, 0.45f, t));
    if (t < 0.75f) return Lerp(c2, c3, SmoothStep(0.45f, 0.75f, t));
    return Lerp(c3, c4, SmoothStep(0.75f, 0.95f, t));
}

var size = context.TileSize;
var seed = GetInt(parameters, "seed", 42);
var variation = GetFloat(parameters, "colorVariation", 0.3f);
var ds = GetFloat(parameters, "duneScale", 0.5f);
var dsh = GetFloat(parameters, "duneSharpness", 0.3f);
var rs = GetFloat(parameters, "rippleStrength", 0.3f);
var rsc = GetFloat(parameters, "rippleScale", 0.5f);
var rd = GetFloat(parameters, "rippleDirection", 0.5f);
var pd = GetFloat(parameters, "pebbleDensity", 0.2f);
var psz = GetFloat(parameters, "pebbleSize", 0.3f);

// Sand palette (RGBA floats)
var deep = (R: 170f / 255f, G: 122f / 255f, B: 70f / 255f);
var shadow = (R: 198f / 255f, G: 152f / 255f, B: 86f / 255f);
var mid = (R: 222f / 255f, G: 184f / 255f, B: 112f / 255f);
var light = (R: 238f / 255f, G: 206f / 255f, B: 136f / 255f);
var highlight = (R: 252f / 255f, G: 232f / 255f, B: 170f / 255f);
var warmTint = (R: 232f / 255f, G: 180f / 255f, B: 104f / 255f);
var coolTint = (R: 204f / 255f, G: 184f / 255f, B: 136f / 255f);
var pebCol = (R: 156f / 255f, G: 118f / 255f, B: 84f / 255f);
var pebHi = (R: 222f / 255f, G: 196f / 255f, B: 148f / 255f);

var result = new PixelBuffer(size, size);
result.ParallelForEachPixel((x, y) =>
{
    var px = x / (float)size * MathF.Tau;
    var py = y / (float)size * MathF.Tau;

    // Dune and contour noise
    var duneFreq = 0.82f + ds * 1.2f;
    var dp = Math.Max(2, (int)(size * duneFreq / MathF.Tau));
    var dune = TileableFractalNoise(x * duneFreq / size * MathF.Tau, y * duneFreq / size * MathF.Tau, dp, 2, 0.56f, 2f, seed);

    var cf = 1.45f + ds * 1.95f;
    var cp = Math.Max(2, (int)(size * cf / MathF.Tau));
    var contour = TileableFractalNoise(x * cf / size * MathF.Tau, y * cf / size * MathF.Tau, cp, 2, 0.54f, 2f, seed + 17);

    // Patch
    var cs = Math.Max(4, size / 6);
    var pp = Math.Max(1, size / cs);
    var patch = TileableValueNoise((float)x / cs, (float)y / cs, pp, seed + 43);

    // Ripples
    var hc = 3 + (int)MathF.Round(rsc * 6f);
    var dr = DirBands(px, py, rd, hc, (contour - 0.5f) * (1.1f + rs * 1.5f));
    var cr = DirBands(px, py, rd + 0.25f, 1 + (int)MathF.Round(ds * 2f), patch * MathF.Tau);

    // Checker
    var chk = ((x + y) & 1) == 0 ? -0.011f : 0.011f;

    // Tone
    var tone = dune * 0.5f + contour * 0.22f + patch * 0.28f;
    tone = Lerp(tone, patch, 0.18f + dsh * 0.22f);
    tone += (dr - 0.5f) * (0.12f + rs * 0.16f);
    tone += (cr - 0.5f) * 0.05f;
    tone = Math.Clamp(tone + chk * (0.36f + rs * 0.58f), 0f, 1f);

    // Base color
    var r = Sel(tone, deep.R, shadow.R, mid.R, light.R, highlight.R);
    var g = Sel(tone, deep.G, shadow.G, mid.G, light.G, highlight.G);
    var b = Sel(tone, deep.B, shadow.B, mid.B, light.B, highlight.B);

    // Color variation
    if (variation > 0.01f)
    {
        var wm = SmoothStep(0.56f, 0.92f, patch) * variation;
        var cm = SmoothStep(0.58f, 0.9f, 1f - contour) * variation * 0.65f;
        r = Lerp(r, warmTint.R, wm * 0.18f);
        g = Lerp(g, warmTint.G, wm * 0.18f);
        b = Lerp(b, warmTint.B, wm * 0.18f);
        r = Lerp(r, coolTint.R, cm * 0.12f);
        g = Lerp(g, coolTint.G, cm * 0.12f);
        b = Lerp(b, coolTint.B, cm * 0.12f);
    }

    // Ripple relief
    if (rs > 0.01f)
    {
        var ridge = SmoothStep(0.76f - rs * 0.08f, 0.98f, dr);
        var trough = SmoothStep(0.02f, 0.2f + rs * 0.1f, 1f - dr);
        r = Lerp(r, highlight.R, ridge * (0.1f + rs * 0.12f));
        g = Lerp(g, highlight.G, ridge * (0.1f + rs * 0.12f));
        b = Lerp(b, highlight.B, ridge * (0.1f + rs * 0.12f));
        r = Lerp(r, deep.R, trough * (0.08f + rs * 0.1f));
        g = Lerp(g, deep.G, trough * (0.08f + rs * 0.1f));
        b = Lerp(b, deep.B, trough * (0.08f + rs * 0.1f));
    }

    // Pebbles
    if (pd > 0.01f)
    {
        var cl = Math.Max(6, (int)MathF.Round(size / (2.8f + pd * 3.2f)));
        var prd = Math.Max(1, size / cl);
        var cx = x / cl;
        var cy = y / cl;
        var lx = x % cl;
        var ly = y % cl;
        var wx = Mod(cx, prd);
        var wy = Mod(cy, prd);

        var roll = HashToUnit(wx, wy, seed + 137);
        if (roll >= 0.94f - pd * 0.22f)
        {
            var pcx = Math.Min(cl - 2, 1 + (int)(HashToUnit(wx, wy, seed + 149) * Math.Max(1, cl - 2)));
            var pcy = Math.Min(cl - 2, 1 + (int)(HashToUnit(wx, wy, seed + 151) * Math.Max(1, cl - 2)));
            var rad = psz >= 0.7f ? 2 : psz >= 0.28f ? 1 : 0;
            var dx = Math.Abs(lx - pcx);
            var dy = Math.Abs(ly - pcy);
            var dist = dx + dy;

            if (dist == 0)
                { r = pebCol.R; g = pebCol.G; b = pebCol.B; }
            else if (rad > 0 && dist <= rad)
            {
                if (dx <= dy)
                    { r = pebHi.R; g = pebHi.G; b = pebHi.B; }
                else
                    { r = pebCol.R; g = pebCol.G; b = pebCol.B; }
            }
        }
    }

    result.SetPixel(x, y, r, g, b, 1f);
});

return result;
